// Shared e2e fixtures — sign-in, channel join, mention dispatch from "other user".

import type { Page } from '@playwright/test';

export interface MemberCtx {
  id: string;
  email: string;
  activeChannelId: string;
}

/** Signs a fresh member in via the project's test-helper sign-in route.
 *  Returns the member's id + active channel id. */
export async function signInAsMember(page: Page, opts: { dnd?: 'off' | 'manual' } = {}): Promise<MemberCtx> {
  const email = `e2e_${Date.now()}_${Math.random().toString(36).slice(2, 7)}@test.local`;
  await page.goto('/_test/seed_member', { waitUntil: 'networkidle' });
  await page.fill('[data-test=seed-email]', email);
  await page.click('[data-test=seed-submit]');
  const memberId = await page.locator('[data-test=seeded-member-id]').innerText();
  const channelId = await page.locator('[data-test=seeded-channel-id]').innerText();

  if (opts.dnd === 'manual') {
    await page.goto(`/_test/set_dnd?member=${memberId}&manual_on=true`);
  }

  // Sign in to the member's session.
  await page.goto('/signin');
  await page.fill('[data-test=signin-email]', email);
  await page.click('[data-test=signin-submit]');
  await page.waitForSelector('[data-test=app-shell]');

  return { id: memberId, email, activeChannelId: channelId };
}

/** Posts a mention message to the given member from a different user via the
 *  test-helper API (so the test driver doesn't need a second browser context). */
export async function sendMentionFromOtherUser(opts: {
  to: MemberCtx;
  channel: string;
  page: Page;
}): Promise<{ msgId: string }> {
  const resp = await opts.page.request.post('/api/_test/post_mention_as_other', {
    data: {
      channel: opts.channel,
      mention_ids: [opts.to.id],
      text: `hey @${opts.to.id} look here`,
    },
  });
  const body = await resp.json();
  return { msgId: body.id };
}

/** Asks the test-helper API to delete a message authored by the "other user". */
export async function deleteMentionMessage(opts: { msgId: string; page: Page }): Promise<void> {
  await opts.page.request.delete(`/api/_test/messages/${opts.msgId}`);
}
